
// ═══ 根容器 - 左右分栏 ═══
// 使用 aspect-ratio 控制高度，避免使用 vh 单位
.app-container {
  display: flex;
  width: 100%;
  // 使用 aspect-ratio 让高度根据宽度动态调整
  // 16:10 比例适合大多数显示场景
  aspect-ratio: 16 / 10;
  background: var(--color-bg-dark);
  overflow: hidden; // 防止内容溢出根容器
}

// ═══ 左侧导航栏 ═══
.sidebar-nav {
  width: 48px;
  min-width: 48px;
  flex-shrink: 0;
  background: var(--color-bg-card);
  border-right: 1px solid var(--color-border);
  display: flex;
  flex-direction: column;
  overflow-y: auto; // 当高度不足时允许滚动

  // 隐藏滚动条但保留功能
  scrollbar-width: none;
  &::-webkit-scrollbar {
    display: none;
  }
}

.nav-list {
  display: flex;
  flex-direction: column;
  padding: var(--spacing-xs) 0;
  gap: 2px;
}

.nav-item {
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
  width: 48px;
  height: 44px;
  color: var(--color-text-muted);
  text-decoration: none;
  transition: all var(--transition-fast);
  border-left: 3px solid transparent;

  i {
    font-size: 18px;
    transition: color var(--transition-fast);
  }

  &:hover {
    background: var(--color-bg-elevated);
    color: var(--color-text-primary);
  }

  &.active {
    background: linear-gradient(90deg, rgba(196, 30, 58, 0.15) 0%, transparent 100%);
    color: var(--color-romance);
    border-left-color: var(--color-romance);
  }

  // ═══ 不同页面的Icon颜色 ═══
  &.nav-dashboard i {
    color: var(--color-gold);
  }
  &.nav-profile i {
    color: #4a90d9;
  }
  &.nav-characters i {
    color: #9b59b6;
  }
  &.nav-romance i {
    color: var(--color-romance);
  }
  &.nav-faction i {
    color: #27ae60;
  }
  &.nav-assets-secrets i {
    color: #e67e22; // 橙色 - 资产暗账
  }
  &.nav-opportunities i {
    color: #1abc9c;
  }
  &.nav-variables i {
    color: #7f8c8d;
  }

  &.active i {
    color: var(--color-romance) !important;
  }
}

.nav-badge {
  position: absolute;
  top: 6px;
  right: 6px;
  min-width: 16px;
  height: 16px;
  padding: 0 4px;
  font-size: 10px;
  font-weight: 600;
  background: var(--color-romance);
  color: white;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
}

// ═══ 右侧主内容区 ═══
.main-wrapper {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-width: 0;
  overflow: hidden; // 防止溢出
}

// ═══ 顶部导航栏 ═══
.app-header {
  position: sticky;
  top: 0;
  z-index: 100;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--spacing-sm) var(--spacing-lg);
  background: linear-gradient(180deg, var(--color-bg-card) 0%, rgba(22, 25, 34, 0.95) 100%);
  border-bottom: 1px solid var(--color-border);
  backdrop-filter: blur(10px);
  flex-shrink: 0;
}

.header-left {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);
}

.app-title {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
}

.title-text {
  font-family: var(--font-display);
  font-size: 18px;
  font-weight: 700;
  background: var(--color-romance-gradient);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.header-center {
  display: flex;
  align-items: center;
  gap: var(--spacing-lg);
  font-size: 13px;
  color: var(--color-text-secondary);

  i {
    margin-right: 4px;
    color: var(--color-gold);
  }

  .location-display i {
    color: #3498db;
  }
}

.header-right {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);
}

.player-info {
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  font-size: 12px;

  .player-name {
    font-weight: 600;
    color: var(--color-text-primary);
  }

  .player-rank {
    color: var(--color-gold);
    font-size: 11px;
  }
}

.char-count {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 4px 10px;
  font-size: 12px;
  color: var(--color-text-secondary);
  background: var(--color-bg-elevated);
  border-radius: var(--radius-full);
  text-decoration: none;
  transition: all var(--transition-fast);

  i {
    color: var(--color-gold);
  }

  &.clickable {
    cursor: pointer;

    &:hover {
      background: var(--color-bg-card);
      color: var(--color-text-primary);
      transform: translateY(-1px);
      box-shadow: 0 2px 8px rgba(0, 0, 0, 0.2);
    }
  }
}

// ═══ MVU重试解析按钮 ═══
.mvu-retry-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  background: transparent;
  border: 1px solid var(--color-gold);
  border-radius: var(--radius-md);
  color: var(--color-gold);
  transition: all var(--transition-fast);
  cursor: pointer;

  &:hover {
    background: rgba(216, 166, 87, 0.15);
    transform: scale(1.05);
  }

  // 解析中状态 - 红色停止图标 + 脉冲动画
  &.parsing {
    border-color: var(--color-danger);
    background: rgba(255, 107, 107, 0.15);
    cursor: pointer; // 可以点击中断

    .abort-icon {
      color: var(--color-danger);
      animation: pulse-abort 1s ease-in-out infinite;
    }

    &:hover {
      background: rgba(255, 107, 107, 0.25);
      transform: scale(1.05);
    }
  }
}

// 中止按钮脉冲动画
@keyframes pulse-abort {
  0%,
  100% {
    opacity: 1;
    transform: scale(1);
  }
  50% {
    opacity: 0.6;
    transform: scale(0.9);
  }
}

// ═══ 设置按钮 ═══
.settings-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  background: transparent;
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  color: var(--color-text-secondary);
  text-decoration: none;
  transition: all var(--transition-fast);

  &:hover {
    background: var(--color-bg-elevated);
    color: var(--color-text-primary);
    border-color: var(--color-text-muted);

    i {
      transform: rotate(90deg);
    }
  }

  i {
    transition: transform var(--transition-normal);
  }
}

// ═══ 主内容区 ═══
.main-content {
  flex: 1;
  padding: var(--spacing-lg);
  overflow-y: scroll; // 内容区域滚动
  overflow-x: hidden;

  // 滚动条样式
  scrollbar-width: thin;
  scrollbar-color: var(--color-border) transparent;

  &::-webkit-scrollbar {
    width: 6px;
  }

  &::-webkit-scrollbar-track {
    background: transparent;
  }

  &::-webkit-scrollbar-thumb {
    background: var(--color-border);
    border-radius: 3px;

    &:hover {
      background: var(--color-text-muted);
    }
  }
}

// ═══ 加载状态 ═══
.loading-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: 100%; // 填满可用空间
  gap: var(--spacing-lg);
  color: var(--color-text-secondary);
}

.loading-spinner {
  width: 40px;
  height: 40px;
  border: 3px solid var(--color-border);
  border-top-color: var(--color-romance);
  border-radius: 50%;
  animation: spin 1s linear infinite;
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}

// ═══ 脏数据提示 (顶部banner) ═══
.dirty-banner {
  position: fixed;
  top: 0;
  left: 48px;
  right: 0;
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  padding: var(--spacing-sm) var(--spacing-lg);
  background: linear-gradient(90deg, rgba(224, 195, 108, 0.15) 0%, rgba(224, 195, 108, 0.05) 100%);
  border-bottom: 1px solid rgba(224, 195, 108, 0.3);
  color: var(--color-warning);
  font-size: 13px;
  z-index: 200;

  .dirty-actions {
    margin-left: auto;
    display: flex;
    gap: var(--spacing-xs);
  }

  .btn-discard {
    padding: 4px 12px;
    background: transparent;
    border: 1px solid var(--color-border);
    border-radius: var(--radius-sm);
    color: var(--color-text-muted);
    font-size: 12px;

    &:hover {
      border-color: var(--color-danger);
      color: var(--color-danger);
    }
  }

  .btn-save {
    padding: 4px 12px;
    background: var(--color-gold);
    border-radius: var(--radius-sm);
    color: var(--color-bg-dark);
    font-size: 12px;
    font-weight: 600;

    &:hover {
      filter: brightness(1.1);
    }
  }
}

// ═══ 过渡动画 ═══
.fade-enter-active,
.fade-leave-active {
  transition: opacity 0.2s ease;
}

.fade-enter-from,
.fade-leave-to {
  opacity: 0;
}

.slide-down-enter-active,
.slide-down-leave-active {
  transition: all 0.2s ease;
}

.slide-down-enter-from,
.slide-down-leave-to {
  transform: translateY(-100%);
  opacity: 0;
}
