
// ═══ 遮罩层 ═══
.modal-overlay {
  position: fixed;
  inset: 0;
  z-index: var(--z-modal);
  display: flex;
  align-items: center;
  justify-content: center;
  padding: var(--spacing-lg);
  background: rgba(0, 0, 0, 0.7);
  backdrop-filter: blur(4px);

  &.no-close-on-click {
    cursor: default;
  }
}

// ═══ 模态框容器 ═══
.modal-container {
  position: relative;
  display: flex;
  flex-direction: column;
  max-height: calc(100% - var(--spacing-2xl) * 2);
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-lg);
  overflow: hidden;

  // 尺寸变体
  &.size-sm {
    width: 320px;
  }

  &.size-md {
    width: 480px;
  }

  &.size-lg {
    width: 640px;
  }

  &.size-xl {
    width: 800px;
  }

  &.size-full {
    width: calc(100% - var(--spacing-2xl) * 2);
    height: calc(100% - var(--spacing-2xl) * 2);
    max-height: none;
  }

  // 最大宽度限制
  max-width: calc(100% - var(--spacing-lg) * 2);
}

// ═══ 头部 ═══
.modal-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--spacing-md) var(--spacing-lg);
  border-bottom: 1px solid var(--color-border);
  background: linear-gradient(180deg, var(--color-bg-elevated) 0%, var(--color-bg-card) 100%);
  flex-shrink: 0;
}

.modal-title {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  font-size: 16px;
  font-weight: 600;
  color: var(--color-text-primary);
  margin: 0;

  i {
    color: var(--color-gold);
  }
}

.modal-close {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 28px;
  height: 28px;
  padding: 0;
  background: transparent;
  border: none;
  border-radius: var(--radius-sm);
  color: var(--color-text-muted);
  cursor: pointer;
  transition: all var(--transition-fast);

  &:hover {
    background: var(--color-bg-elevated);
    color: var(--color-text-primary);
  }

  &:active {
    background: rgba(255, 107, 107, 0.1);
    color: var(--color-danger);
  }
}

// ═══ 内容 ═══
.modal-body {
  flex: 1;
  padding: var(--spacing-lg);
  overflow-y: auto;

  &.no-padding {
    padding: 0;
  }

  // 滚动条样式
  scrollbar-width: thin;
  scrollbar-color: var(--color-border) transparent;

  &::-webkit-scrollbar {
    width: 6px;
  }

  &::-webkit-scrollbar-track {
    background: transparent;
  }

  &::-webkit-scrollbar-thumb {
    background: var(--color-border);
    border-radius: 3px;

    &:hover {
      background: var(--color-text-muted);
    }
  }
}

// ═══ 底部 ═══
.modal-footer {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: var(--spacing-sm);
  padding: var(--spacing-md) var(--spacing-lg);
  border-top: 1px solid var(--color-border);
  background: var(--color-bg-elevated);
  flex-shrink: 0;
}

// ═══ 过渡动画 ═══
.modal-enter-active,
.modal-leave-active {
  transition: opacity 0.2s ease;

  .modal-container {
    transition: transform 0.2s ease, opacity 0.2s ease;
  }
}

.modal-enter-from,
.modal-leave-to {
  opacity: 0;

  .modal-container {
    transform: scale(0.95) translateY(-10px);
    opacity: 0;
  }
}
