
.image-uploader {
  width: 100%;
}

// ═══ 上传区域 ═══
.upload-zone {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: var(--spacing-sm);
  padding: var(--spacing-xl);
  background: var(--color-bg-elevated);
  border: 2px dashed var(--color-border);
  border-radius: var(--radius-lg);
  cursor: pointer;
  transition: all var(--transition-fast);
  min-height: 120px;

  &:hover {
    border-color: var(--color-gold);
    background: rgba(216, 166, 87, 0.05);
  }

  &.dragging {
    border-color: var(--color-gold);
    background: rgba(216, 166, 87, 0.1);
    transform: scale(1.02);
  }

  &.has-image {
    padding: var(--spacing-sm);
    position: relative;

    &:hover .preview-overlay {
      opacity: 1;
    }
  }

  > i {
    font-size: 32px;
    color: var(--color-text-muted);
  }

  > span {
    font-size: 13px;
    color: var(--color-text-secondary);
  }

  .hint {
    font-size: 11px;
    color: var(--color-text-muted);
  }
}

.preview-img {
  max-width: 100%;
  max-height: 200px;
  object-fit: contain;
  border-radius: var(--radius-md);

  &.circle {
    border-radius: 50%;
  }
}

.preview-overlay {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(0, 0, 0, 0.6);
  border-radius: var(--radius-lg);
  opacity: 0;
  transition: opacity var(--transition-fast);

  span {
    color: white;
    font-size: 14px;
    font-weight: 500;
  }
}

// ═══ 裁剪弹窗 ═══
.cropper-modal {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(0, 0, 0, 0.85);
  backdrop-filter: blur(4px);
  z-index: 99999;
}

.cropper-dialog {
  width: 500px;
  max-width: 95vw;
  background: var(--color-bg-card);
  border-radius: var(--radius-lg);
  border: 1px solid var(--color-border);
  overflow: hidden;
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.5);
}

.cropper-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--spacing-md) var(--spacing-lg);
  border-bottom: 1px solid var(--color-border);

  h3 {
    display: flex;
    align-items: center;
    gap: var(--spacing-sm);
    font-size: 16px;
    font-weight: 600;
    color: var(--color-text-primary);
    margin: 0;

    i {
      color: var(--color-gold);
    }
  }

  .close-btn {
    width: 32px;
    height: 32px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: transparent;
    border: none;
    border-radius: var(--radius-sm);
    color: var(--color-text-muted);
    cursor: pointer;

    &:hover {
      background: var(--color-bg-elevated);
      color: var(--color-text-primary);
    }
  }
}

.cropper-body {
  padding: var(--spacing-lg);
}

// Canvas 容器
.canvas-container {
  position: relative;
  width: 400px;
  height: 320px;
  margin: 0 auto var(--spacing-lg);
  background: #1a1a1a;
  border-radius: var(--radius-md);
  overflow: hidden;
  cursor: move;

  canvas {
    display: block;
  }
}

// 裁剪框
.crop-frame {
  position: absolute;
  border: 2px solid var(--color-gold);
  box-shadow: 0 0 0 9999px rgba(0, 0, 0, 0.5);
  pointer-events: none;

  &.circle {
    border-radius: 50%;
  }

  &.portrait {
    border-radius: var(--radius-md);
  }

  &.square {
    border-radius: var(--radius-md);
  }
}

// ═══ 工具栏 ═══
.cropper-tools {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-lg);
  padding: var(--spacing-md);
  background: var(--color-bg-elevated);
  border-radius: var(--radius-md);
}

.tool-group {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-xs);
}

.tool-label {
  font-size: 11px;
  color: var(--color-text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.zoom-control {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);

  button {
    width: 28px;
    height: 28px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: var(--color-bg-card);
    border: 1px solid var(--color-border);
    border-radius: var(--radius-sm);
    color: var(--color-text-secondary);
    cursor: pointer;

    &:hover {
      border-color: var(--color-gold);
      color: var(--color-gold);
    }
  }

  .zoom-value {
    font-size: 12px;
    color: var(--color-text-secondary);
    min-width: 50px;
    text-align: center;
  }
}

.tool-group select {
  padding: var(--spacing-xs) var(--spacing-sm);
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  color: var(--color-text-primary);
  font-size: 13px;
}

// ═══ 底部按钮 ═══
.cropper-footer {
  display: flex;
  justify-content: flex-end;
  gap: var(--spacing-sm);
  padding: var(--spacing-md) var(--spacing-lg);
  border-top: 1px solid var(--color-border);
}

.btn-cancel {
  padding: var(--spacing-sm) var(--spacing-lg);
  background: transparent;
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  font-size: 13px;
  color: var(--color-text-secondary);
  cursor: pointer;

  &:hover {
    background: var(--color-bg-elevated);
    color: var(--color-text-primary);
  }
}

.btn-confirm {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
  padding: var(--spacing-sm) var(--spacing-lg);
  background: var(--color-gold);
  border: none;
  border-radius: var(--radius-md);
  font-size: 13px;
  font-weight: 600;
  color: var(--color-bg-dark);
  cursor: pointer;

  &:hover {
    filter: brightness(1.1);
  }
}
