
.masked-text {
  position: relative;
  display: inline-block;
  min-width: 60px;
}

// 遮罩层
.mask-overlay {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(15, 17, 23, 0.9);
  backdrop-filter: blur(4px);
  -webkit-backdrop-filter: blur(4px);
  border-radius: var(--radius-sm);
  cursor: pointer;
  z-index: 2;
  transition: all var(--transition-fast);

  &:hover {
    background: rgba(15, 17, 23, 0.8);

    .mask-content {
      color: var(--color-gold);
    }
  }
}

.mask-content {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
  color: var(--color-text-muted);
  font-size: 11px;
  transition: color var(--transition-fast);

  i {
    font-size: 16px;
  }
}

// 内容区域
.content {
  transition: filter var(--transition-normal);

  &.blurred {
    filter: blur(8px);
    user-select: none;
    pointer-events: none;
  }
}

// 手动遮罩按钮
.lock-btn {
  position: absolute;
  top: 4px;
  right: 4px;
  width: 20px;
  height: 20px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--color-bg-elevated);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  color: var(--color-text-muted);
  font-size: 10px;
  cursor: pointer;
  z-index: 1;
  opacity: 0;
  transition: all var(--transition-fast);

  .masked-text:hover & {
    opacity: 1;
  }

  &:hover {
    background: var(--color-bg-card);
    color: var(--color-text-primary);
    border-color: var(--color-gold);
  }
}

// 倒计时
.countdown {
  position: absolute;
  bottom: 4px;
  right: 4px;
  padding: 2px 6px;
  background: rgba(0, 0, 0, 0.6);
  border-radius: var(--radius-sm);
  font-size: 10px;
  color: var(--color-text-muted);
  z-index: 1;
}
