
.mvu-confirm-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.6);
  backdrop-filter: blur(4px);
  display: flex;
  align-items: flex-end;
  justify-content: center;
  padding: var(--spacing-lg);
  z-index: var(--z-modal);
}

.mvu-confirm-dialog {
  width: 100%;
  max-width: 700px;
  max-height: 80vh;
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  display: flex;
  flex-direction: column;
  box-shadow: var(--shadow-lg);
  transition: all 0.3s ease;

  &.collapsed {
    max-height: auto;
  }
}

// ═══ Header ═══
.dialog-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--spacing-md) var(--spacing-lg);
  background: var(--color-bg-elevated);
  border-bottom: 1px solid var(--color-border);
  border-radius: var(--radius-lg) var(--radius-lg) 0 0;
}

.header-title {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  font-size: 16px;
  font-weight: 600;
  color: var(--color-text-primary);

  i {
    color: var(--color-gold);
  }
}

.header-actions {
  display: flex;
  gap: var(--spacing-xs);
}

.btn-action {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 32px;
  height: 32px;
  background: transparent;
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  color: var(--color-text-muted);
  transition: all var(--transition-fast);

  &:hover {
    background: var(--color-bg-dark);
    color: var(--color-text-primary);
  }

  &.btn-close:hover {
    color: var(--color-danger);
    border-color: var(--color-danger);
  }
}

// ═══ Body ═══
.dialog-body {
  flex: 1;
  overflow-y: auto;
  padding: var(--spacing-lg);
  display: flex;
  flex-direction: column;
  gap: var(--spacing-lg);
}

.section-label {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
  font-size: 13px;
  font-weight: 600;
  color: var(--color-text-secondary);
  margin-bottom: var(--spacing-sm);

  i {
    color: var(--color-gold);
  }
}

.label-hint {
  margin-left: auto;
  font-size: 11px;
  font-weight: 400;
  color: var(--color-text-muted);
  background: var(--color-bg-dark);
  padding: 2px 6px;
  border-radius: var(--radius-sm);
}

.preview-content {
  padding: var(--spacing-md);
  background: var(--color-bg-dark);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  font-size: 13px;
  line-height: 1.6;
}

.message-preview {
  max-height: 100px;
  overflow-y: auto;
  color: var(--color-text-secondary);
  white-space: pre-wrap;
  word-break: break-word;
}

// ═══ Code Editor ═══
.code-editor {
  width: 100%;
  min-height: 150px;
  padding: var(--spacing-md);
  background: var(--color-bg-dark);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  font-family: var(--font-mono);
  font-size: 13px;
  line-height: 1.6;
  color: var(--color-text-primary);
  resize: vertical;
  transition: border-color var(--transition-fast);

  &:focus {
    border-color: var(--color-gold);
    outline: none;
  }
}

// ═══ Parsed Preview ═══
.parsed-preview {
  max-height: 250px;
  overflow-y: auto;
}

.command-item {
  display: flex;
  flex-wrap: wrap;
  align-items: flex-start;
  gap: var(--spacing-sm);
  padding: var(--spacing-xs) 0;
  font-family: var(--font-mono);
  font-size: 12px;
  line-height: 1.4;

  & + & {
    border-top: 1px solid var(--color-border);
  }
}

.cmd-type {
  padding: 2px 6px;
  border-radius: var(--radius-sm);
  font-weight: 600;
  text-transform: uppercase;
  font-size: 10px;

  &.type-set {
    background: rgba(74, 193, 142, 0.2);
    color: var(--color-success);
  }

  &.type-add {
    background: rgba(122, 162, 247, 0.2);
    color: var(--color-info);
  }

  &.type-insert,
  &.type-assign {
    background: rgba(216, 166, 87, 0.2);
    color: var(--color-gold);
  }

  &.type-delete,
  &.type-remove,
  &.type-unset {
    background: rgba(255, 107, 107, 0.2);
    color: var(--color-danger);
  }
}

.cmd-path {
  color: var(--color-text-primary);
}

.cmd-path {
  word-break: break-all;
}

.cmd-value {
  color: var(--color-success);
  word-break: break-all;
  flex: 1;
  min-width: 0;
}

.cmd-reason {
  width: 100%;
  color: var(--color-text-muted);
  font-style: italic;
  margin-top: var(--spacing-xs);
}

.no-commands {
  color: var(--color-text-muted);
  text-align: center;
  padding: var(--spacing-md);
}

// ═══ Footer ═══
.dialog-footer {
  display: flex;
  justify-content: flex-end;
  gap: var(--spacing-sm);
  padding: var(--spacing-md) var(--spacing-lg);
  border-top: 1px solid var(--color-border);
}

.btn-secondary,
.btn-primary {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
  padding: var(--spacing-sm) var(--spacing-lg);
  border-radius: var(--radius-md);
  font-size: 14px;
  font-weight: 600;
  transition: all var(--transition-fast);
}

.btn-secondary {
  background: transparent;
  border: 1px solid var(--color-border);
  color: var(--color-text-secondary);

  &:hover {
    background: var(--color-bg-elevated);
    color: var(--color-text-primary);
  }
}

.btn-primary {
  background: var(--color-gold);
  color: var(--color-bg-dark);

  &:hover:not(:disabled) {
    filter: brightness(1.1);
  }

  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
  }
}

// ═══ Collapsed Content ═══
.collapsed-content {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--spacing-md) var(--spacing-lg);
}

.collapsed-info {
  font-size: 13px;
  color: var(--color-text-secondary);
}

.btn-mini {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
  padding: var(--spacing-xs) var(--spacing-sm);
  background: var(--color-gold);
  border-radius: var(--radius-sm);
  color: var(--color-bg-dark);
  font-size: 12px;
  font-weight: 600;

  &:hover {
    filter: brightness(1.1);
  }
}

// ═══ Transitions ═══
.modal-enter-active,
.modal-leave-active {
  transition: all 0.3s ease;

  .mvu-confirm-dialog {
    transition: all 0.3s ease;
  }
}

.modal-enter-from,
.modal-leave-to {
  opacity: 0;

  .mvu-confirm-dialog {
    transform: translateY(100%);
  }
}
