
// ═══ 遮罩层 ═══
.drawer-overlay {
  position: fixed;
  inset: 0;
  z-index: var(--z-drawer);
  background: rgba(0, 0, 0, 0.6);
  backdrop-filter: blur(2px);
}

// ═══ 抽屉容器 ═══
.drawer-container {
  position: fixed;
  top: 0;
  right: 0;
  width: 420px;
  max-width: 90vw;
  height: 100%;
  background: var(--color-bg-card);
  border-left: 1px solid var(--color-border);
  display: flex;
  flex-direction: column;
  overflow: hidden;

  &.editing {
    width: 500px;
  }
}

// ═══ 头部 ═══
.drawer-header {
  display: flex;
  align-items: flex-start;
  gap: var(--spacing-md);
  padding: var(--spacing-lg);
  background: linear-gradient(135deg, rgba(216, 166, 87, 0.1) 0%, transparent 100%);
  border-bottom: 1px solid var(--color-border);
  flex-shrink: 0;
}

.header-avatar {
  position: relative;
  width: 72px;
  height: 72px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--color-bg-elevated);
  border-radius: 50%; // 圆形显示，与裁剪形状一致
  overflow: hidden;
  flex-shrink: 0;
  cursor: pointer;

  img {
    width: 100%;
    height: 100%;
    object-fit: cover;
  }

  > i {
    font-size: 28px;
    color: var(--color-text-muted);
  }

  &.male {
    border: 2px solid #4a90d9;
  }

  &.female {
    border: 2px solid #e84393;
  }

  // 上传覆盖层
  .avatar-upload-overlay {
    position: absolute;
    inset: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    background: rgba(0, 0, 0, 0.6);
    border-radius: 50%;
    opacity: 0;
    transition: opacity 0.2s ease;

    i {
      font-size: 20px;
      color: white;
    }
  }

  &:hover .avatar-upload-overlay {
    opacity: 1;
  }
}

.gender-badge {
  position: absolute;
  bottom: -4px;
  right: -4px;
  width: 20px;
  height: 20px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 50%;
  font-size: 10px;

  &.male {
    background: #4a90d9;
    color: white;
  }

  &.female {
    background: #e84393;
    color: white;
  }
}

.header-info {
  flex: 1;
  min-width: 0;

  .char-name {
    font-size: 18px;
    font-weight: 600;
    color: var(--color-text-primary);
    margin: 0 0 4px;
  }

  .char-title {
    font-size: 13px;
    color: var(--color-gold);
    display: block;
    margin-bottom: var(--spacing-xs);
  }

  .char-tags {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
  }

  .tag {
    padding: 2px 6px;
    font-size: 10px;
    background: var(--color-bg-elevated);
    border-radius: var(--radius-sm);
    color: var(--color-text-muted);

    &.gold {
      background: rgba(216, 166, 87, 0.15);
      color: var(--color-gold);
    }
    &.romance {
      background: rgba(255, 77, 109, 0.15);
      color: var(--color-romance-light);
    }
    &.danger {
      background: rgba(255, 107, 107, 0.15);
      color: var(--color-danger);
    }
    &.info {
      background: rgba(122, 162, 247, 0.15);
      color: var(--color-info);
    }
  }
}

.drawer-close {
  width: 32px;
  height: 32px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--color-text-muted);
  border-radius: var(--radius-sm);

  &:hover {
    background: var(--color-bg-elevated);
    color: var(--color-text-primary);
  }
}

// ═══ 内容区 ═══
.drawer-body {
  flex: 1;
  overflow-y: auto;
  padding: var(--spacing-lg);

  &.editing {
    padding: var(--spacing-md);
  }
}

// ═══ 详情区块 ═══
.detail-section {
  margin-bottom: var(--spacing-xl);

  h4 {
    display: flex;
    align-items: center;
    gap: var(--spacing-sm);
    font-size: 13px;
    font-weight: 600;
    color: var(--color-text-primary);
    margin: 0 0 var(--spacing-md);
    padding-bottom: var(--spacing-sm);
    border-bottom: 1px solid var(--color-border);

    i {
      color: var(--color-gold);
    }
  }

  &.romance h4 i {
    color: var(--color-romance-light);
  }
}

.info-grid,
.relation-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: var(--spacing-sm) var(--spacing-md);
}

.info-item,
.relation-item {
  display: flex;
  flex-direction: column;
  gap: 2px;

  &.full {
    grid-column: 1 / -1;
  }

  .label {
    font-size: 11px;
    color: var(--color-text-muted);
    text-transform: uppercase;
    letter-spacing: 0.5px;
  }

  .value {
    font-size: 13px;
    color: var(--color-text-secondary);

    &.male {
      color: #4a90d9;
    }
    &.female {
      color: #e84393;
    }
    &.romance {
      color: var(--color-romance-light);
    }
    &.danger {
      color: var(--color-danger);
    }

    // 年龄值显示
    &.age-value {
      display: flex;
      flex-direction: column;
      gap: 2px;
    }
  }

  // 年龄红线提示
  .age-warning {
    font-size: 10px;
    font-weight: 600;
    padding: 2px 6px;
    border-radius: var(--radius-sm);

    &.danger {
      background: rgba(255, 107, 107, 0.15);
      color: var(--color-danger);
    }
    &.warning {
      background: rgba(224, 195, 108, 0.15);
      color: var(--color-warning);
    }
    &.caution {
      background: rgba(216, 166, 87, 0.15);
      color: var(--color-gold);
    }
    &.good {
      background: rgba(74, 193, 142, 0.15);
      color: var(--color-success);
    }
  }
}

// ═══ 数值面板 ═══
.stats-panel {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-md);
}

.stat-row {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);

  .stat-label {
    width: 50px;
    font-size: 12px;
    color: var(--color-text-muted);
  }

  .stat-bar {
    flex: 1;
    height: 8px;
    background: var(--color-bg-elevated);
    border-radius: 4px;
    overflow: hidden;

    .fill {
      height: 100%;
      border-radius: 4px;
      transition: width 0.3s;

      &.high {
        background: linear-gradient(90deg, var(--color-success), #6dd5a0);
      }
      &.mid {
        background: linear-gradient(90deg, var(--color-warning), #f0d78c);
      }
      &.low {
        background: linear-gradient(90deg, var(--color-danger), #ff9999);
      }
    }
  }

  .stat-value {
    width: 30px;
    text-align: right;
    font-size: 13px;
    font-weight: 600;

    &.high {
      color: var(--color-success);
    }
    &.mid {
      color: var(--color-warning);
    }
    &.low {
      color: var(--color-danger);
    }
  }
}

// ═══ 危险度条 ═══
.danger-bar-wrapper {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
}

.danger-bar {
  flex: 1;
  height: 6px;
  background: var(--color-bg-elevated);
  border-radius: 3px;
  overflow: hidden;

  .fill {
    height: 100%;
    background: var(--color-romance-gradient);
    border-radius: 3px;
  }
}

.danger-value {
  font-size: 12px;
  font-weight: 600;
  color: var(--color-romance-light);
}

.status-text {
  font-size: 13px;
  line-height: 1.6;
  color: var(--color-text-secondary);
}

// ═══ 操作按钮 ═══
.drawer-actions {
  display: flex;
  gap: var(--spacing-md);
  margin-top: var(--spacing-lg);
  padding-top: var(--spacing-lg);
  border-top: 1px solid var(--color-border);
}

.btn-edit {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  padding: var(--spacing-sm) var(--spacing-md);
  background: var(--color-gold);
  border-radius: var(--radius-md);
  font-size: 13px;
  font-weight: 600;
  color: var(--color-bg-dark);

  &:hover {
    filter: brightness(1.1);
  }
}

.btn-delete {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  padding: var(--spacing-sm) var(--spacing-md);
  background: transparent;
  border: 1px solid var(--color-danger);
  border-radius: var(--radius-md);
  font-size: 13px;
  color: var(--color-danger);

  &:hover {
    background: rgba(255, 107, 107, 0.1);
  }
}

// ═══ 编辑操作 ═══
.edit-actions {
  display: flex;
  gap: var(--spacing-md);
  margin-top: var(--spacing-lg);
  padding-top: var(--spacing-lg);
  border-top: 1px solid var(--color-border);
}

.btn-cancel {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  padding: var(--spacing-sm) var(--spacing-md);
  background: transparent;
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  font-size: 13px;
  color: var(--color-text-secondary);

  &:hover {
    background: var(--color-bg-elevated);
    color: var(--color-text-primary);
  }
}

.btn-save {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  padding: var(--spacing-sm) var(--spacing-md);
  background: var(--color-success);
  border-radius: var(--radius-md);
  font-size: 13px;
  font-weight: 600;
  color: white;

  &:hover:not(:disabled) {
    filter: brightness(1.1);
  }

  &:disabled {
    opacity: 0.6;
    cursor: not-allowed;
  }
}

// ═══ 过渡动画 ═══
.drawer-enter-active,
.drawer-leave-active {
  transition: opacity 0.3s ease;

  .drawer-container {
    transition: transform 0.3s ease;
  }
}

.drawer-enter-from,
.drawer-leave-to {
  opacity: 0;

  .drawer-container {
    transform: translateX(100%);
  }
}

// ═══ 头像上传弹窗 ═══
.avatar-uploader-modal {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(0, 0, 0, 0.8);
  backdrop-filter: blur(4px);
  z-index: 10000; // 需要高于 drawer

  .uploader-dialog {
    width: 460px;
    max-width: 95vw;
    background: var(--color-bg-card);
    border-radius: var(--radius-lg);
    border: 1px solid var(--color-border);
    overflow: hidden;
    box-shadow: 0 20px 60px rgba(0, 0, 0, 0.5);
  }

  .uploader-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: var(--spacing-md) var(--spacing-lg);
    border-bottom: 1px solid var(--color-border);

    h3 {
      display: flex;
      align-items: center;
      gap: var(--spacing-sm);
      font-size: 16px;
      font-weight: 600;
      color: var(--color-text-primary);
      margin: 0;

      i { color: var(--color-gold); }
    }

    .close-btn {
      width: 32px;
      height: 32px;
      display: flex;
      align-items: center;
      justify-content: center;
      background: transparent;
      border-radius: var(--radius-sm);
      color: var(--color-text-muted);

      &:hover {
        background: var(--color-bg-elevated);
        color: var(--color-text-primary);
      }
    }
  }

  .uploader-body {
    padding: var(--spacing-lg);
  }
}
