
.opportunities-page {
  display: flex;
  flex-direction: column;
  height: 100%;
}

// ═══ 看板视图 ═══
.kanban-view {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: var(--spacing-md);
  flex: 1;
  min-height: 0;
}

.kanban-column {
  display: flex;
  flex-direction: column;
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  overflow: hidden;
  min-height: 0;
  transition: transform var(--transition-fast),
              box-shadow var(--transition-fast);

  &:hover {
    transform: translateY(-2px);
    box-shadow: 0 8px 24px rgba(0, 0, 0, 0.2);
  }

  &.danger-column {
    border-top: 3px solid var(--color-danger);
    &:hover { box-shadow: 0 8px 24px rgba(255, 107, 107, 0.15); }
  }
  &.success-column {
    border-top: 3px solid var(--color-success);
    &:hover { box-shadow: 0 8px 24px rgba(74, 193, 142, 0.15); }
  }
  &.todo-column {
    border-top: 3px solid var(--color-info);
    &:hover { box-shadow: 0 8px 24px rgba(122, 162, 247, 0.15); }
  }
}

.column-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--spacing-md);
  border-bottom: 1px solid var(--color-border);
  flex-shrink: 0;

  h3 {
    display: flex;
    align-items: center;
    gap: var(--spacing-sm);
    font-size: 14px;
    font-weight: 600;
    color: var(--color-text-primary);

    i {
      font-size: 12px;
    }
  }

  .danger-column & h3 i { color: var(--color-danger); }
  .success-column & h3 i { color: var(--color-success); }
  .todo-column & h3 i { color: var(--color-info); }

  .column-count {
    padding: 2px 8px;
    font-size: 11px;
    font-weight: 600;
    background: var(--color-bg-elevated);
    border-radius: var(--radius-full);
    color: var(--color-text-muted);
  }
}

.column-body {
  flex: 1;
  padding: var(--spacing-md);
  overflow-y: auto;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-sm);
}

.kanban-card {
  display: flex;
  align-items: flex-start;
  gap: 8px;
  padding: var(--spacing-md);
  background: var(--color-bg-elevated);
  border-radius: var(--radius-md);
  border-left: 3px solid;
  transition: all var(--transition-fast);

  &:hover:not(.completed) {
    background: rgba(255, 255, 255, 0.04);
    transform: translateX(2px);
  }

  &.danger {
    border-left-color: var(--color-danger);
    &:hover:not(.completed) { box-shadow: inset 0 0 0 1px rgba(255, 107, 107, 0.2); }
  }
  &.success {
    border-left-color: var(--color-success);
    &:hover:not(.completed) { box-shadow: inset 0 0 0 1px rgba(74, 193, 142, 0.2); }
  }
  &.todo {
    border-left-color: var(--color-info);
    &:hover:not(.completed) { box-shadow: inset 0 0 0 1px rgba(122, 162, 247, 0.2); }

    &.urgent {
      border-left-color: var(--color-danger);
      &:hover:not(.completed) { box-shadow: inset 0 0 0 1px rgba(255, 107, 107, 0.2); }
    }
    &.high {
      border-left-color: var(--color-warning);
      &:hover:not(.completed) { box-shadow: inset 0 0 0 1px rgba(224, 195, 108, 0.2); }
    }
  }

  &.completed {
    opacity: 0.5;

    .kanban-title, .kanban-content {
      text-decoration: line-through;
      color: var(--color-text-muted);
    }
  }
}

// Todo checkbox
.todo-checkbox {
  position: relative;
  display: flex;
  align-items: center;
  cursor: pointer;
  flex-shrink: 0;
  margin-top: 2px;

  input {
    position: absolute;
    opacity: 0;
    cursor: pointer;
    height: 0;
    width: 0;
  }

  .checkmark {
    width: 16px;
    height: 16px;
    border: 2px solid var(--color-border);
    border-radius: 4px;
    background: transparent;
    transition: all var(--transition-fast);
    display: flex;
    align-items: center;
    justify-content: center;

    &::after {
      content: '';
      display: none;
      width: 4px;
      height: 8px;
      border: solid var(--color-success);
      border-width: 0 2px 2px 0;
      transform: rotate(45deg);
      margin-bottom: 2px;
    }
  }

  input:checked + .checkmark {
    border-color: var(--color-success);
    background: rgba(74, 193, 142, 0.1);

    &::after { display: block; }
}

  &:hover .checkmark {
    border-color: var(--color-text-muted);
  }
}

.card-content {
  flex: 1;
  min-width: 0;
}

.kanban-card-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: var(--spacing-sm);
  margin-bottom: var(--spacing-xs);
}

.kanban-title {
  font-size: 13px;
  font-weight: 600;
  color: var(--color-text-primary);
  line-height: 1.3;
  flex: 1;
}

.level-badge, .urgency-badge {
  padding: 2px 6px;
  font-size: 9px;
  font-weight: 600;
  border-radius: var(--radius-sm);
  background: var(--color-bg-card);
  color: var(--color-text-muted);
  white-space: nowrap;

  &.legendary {
    background: linear-gradient(90deg, #ffd700, #ffec8b);
    color: var(--color-bg-dark);
  }
  &.epic, &.good {
    background: rgba(74, 193, 142, 0.2);
    color: var(--color-success);
  }
  &.fatal {
    background: rgba(255, 107, 107, 0.2);
    color: var(--color-danger);
  }
  &.severe, &.moderate {
    background: rgba(224, 195, 108, 0.2);
    color: var(--color-warning);
  }
  &.urgent {
    background: rgba(255, 107, 107, 0.2);
    color: var(--color-danger);
  }
  &.high {
    background: rgba(224, 195, 108, 0.2);
    color: var(--color-warning);
  }
}

.kanban-content {
  font-size: 12px;
  line-height: 1.5;
  color: var(--color-text-secondary);
  margin-bottom: var(--spacing-sm);
  word-break: break-word;
}

// 详情区域
.kanban-details {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.detail-row {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-sm);
  font-size: 11px;
  color: var(--color-text-muted);

  i {
    margin-right: 3px;
    font-size: 10px;
  }

  &.solution {
    color: var(--color-info);
    font-style: italic;
  }

  &.resource {
    color: var(--color-success);
  }

  &.warning {
    color: var(--color-warning);
  }

  .high-prob {
    color: var(--color-danger);
  }
  .mid-prob {
    color: var(--color-warning);
  }
}

.kanban-meta {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  font-size: 11px;
  color: var(--color-text-muted);

  i {
    margin-right: 3px;
  }
}

.deadline-badge {
  padding: 2px 6px;
  background: var(--color-bg-card);
  border-radius: var(--radius-sm);
  font-size: 10px;
}

.related-avatars {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
}

.mini-char {
  padding: 2px 6px;
  background: var(--color-bg-card);
  border-radius: var(--radius-sm);
  font-size: 10px;
  color: var(--color-text-secondary);
}

.more-chars {
  font-size: 10px;
  color: var(--color-text-muted);
}

.empty-column {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: var(--spacing-sm);
  padding: var(--spacing-xl);
  color: var(--color-text-muted);
  font-size: 12px;

  i {
    font-size: 24px;
    opacity: 0.5;
  }
}
