
.settings-page {
  max-width: 800px;
  margin: 0 auto;
}

.page-header {
  margin-bottom: var(--spacing-xl);
}

.page-title {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  font-size: 24px;
  font-weight: 700;
  color: var(--color-text-primary);

  i {
    color: var(--color-gold);
  }
}

.page-desc {
  margin-top: var(--spacing-xs);
  color: var(--color-text-muted);
  font-size: 14px;
}

.settings-content {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-xl);
}

// ═══ Section ═══
.settings-section {
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  overflow: hidden;
}

.section-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--spacing-md) var(--spacing-lg);
  background: var(--color-bg-elevated);
  border-bottom: 1px solid var(--color-border);

  h2 {
    display: flex;
    align-items: center;
    gap: var(--spacing-sm);
    font-size: 16px;
    font-weight: 600;
    color: var(--color-text-primary);

    i {
      color: var(--color-gold);
    }
  }
}

.section-body {
  padding: var(--spacing-lg);
  display: flex;
  flex-direction: column;
  gap: var(--spacing-md);
}

// ═══ Setting Items ═══
.setting-item {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-xs);

  &.toggle-item {
    flex-direction: row;
    align-items: center;
    justify-content: space-between;
  }
}

.setting-info {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.setting-label {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
  font-size: 14px;
  font-weight: 500;
  color: var(--color-text-primary);

  i {
    color: var(--color-text-muted);
    font-size: 12px;
  }
}

.setting-desc {
  font-size: 12px;
  color: var(--color-text-muted);
}

.setting-input,
.setting-select {
  padding: var(--spacing-sm) var(--spacing-md);
  background: var(--color-bg-dark);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  color: var(--color-text-primary);
  font-size: 14px;
  transition: border-color var(--transition-fast);

  &:focus {
    border-color: var(--color-gold);
    outline: none;
  }

  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
  }
}

.setting-error {
  font-size: 12px;
  color: var(--color-danger);
}

// ═══ Toggle Switch ═══
.toggle-switch {
  position: relative;
  display: inline-block;
  width: 48px;
  height: 26px;

  input {
    opacity: 0;
    width: 0;
    height: 0;
  }
}

.toggle-slider {
  position: absolute;
  cursor: pointer;
  inset: 0;
  background-color: var(--color-bg-dark);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-full);
  transition: var(--transition-fast);

  &::before {
    position: absolute;
    content: '';
    height: 18px;
    width: 18px;
    left: 3px;
    bottom: 3px;
    background-color: var(--color-text-muted);
    border-radius: 50%;
    transition: var(--transition-fast);
  }
}

input:checked + .toggle-slider {
  background-color: var(--color-gold);
  border-color: var(--color-gold);

  &::before {
    transform: translateX(22px);
    background-color: var(--color-bg-dark);
  }
}

// ═══ Status ═══
.extra-model-status {
  padding: var(--spacing-sm) var(--spacing-md);
  background: var(--color-bg-dark);
  border-radius: var(--radius-md);
  margin-top: var(--spacing-sm);
}

.status-item {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  font-size: 13px;
  color: var(--color-text-secondary);

  i {
    font-size: 8px;

    &.status-ready {
      color: var(--color-success);
    }

    &.status-parsing {
      color: var(--color-warning);
      animation: pulse 1s infinite;
    }

    &.status-warning {
      color: var(--color-danger);
    }
  }
}

@keyframes pulse {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.5;
  }
}

// ═══ Profile Controls ═══
.profile-controls {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
}

.profile-select {
  padding: var(--spacing-xs) var(--spacing-sm);
  background: var(--color-bg-dark);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  color: var(--color-text-primary);
  font-size: 13px;
}

.btn-icon {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 28px;
  height: 28px;
  background: var(--color-bg-dark);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  color: var(--color-text-secondary);
  transition: all var(--transition-fast);

  &:hover {
    background: var(--color-bg-elevated);
    color: var(--color-gold);
    border-color: var(--color-gold);
  }

  &.btn-danger:hover {
    color: var(--color-danger);
    border-color: var(--color-danger);
  }
}

// ═══ Input with Toggle ═══
.input-with-toggle {
  display: flex;
  gap: var(--spacing-xs);

  .setting-input {
    flex: 1;
  }

  .btn-toggle {
    padding: var(--spacing-sm);
    background: var(--color-bg-dark);
    border: 1px solid var(--color-border);
    border-radius: var(--radius-md);
    color: var(--color-text-muted);

    &:hover {
      color: var(--color-text-primary);
    }
  }
}

// ═══ Model Selector ═══
.model-selector {
  display: flex;
  gap: var(--spacing-sm);

  .setting-select {
    flex: 1;
  }
}

.btn-fetch {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
  padding: var(--spacing-sm) var(--spacing-md);
  background: var(--color-gold);
  border-radius: var(--radius-md);
  color: var(--color-bg-dark);
  font-size: 13px;
  font-weight: 600;
  transition: all var(--transition-fast);

  &:hover:not(:disabled) {
    filter: brightness(1.1);
  }

  &:disabled {
    opacity: 0.6;
    cursor: not-allowed;
  }
}

// ═══ Advanced Params ═══
.advanced-params {
  margin-top: var(--spacing-md);
  border-top: 1px solid var(--color-border);
  padding-top: var(--spacing-md);
}

.btn-expand {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
  padding: var(--spacing-xs) 0;
  color: var(--color-text-muted);
  font-size: 13px;
  transition: color var(--transition-fast);

  &:hover {
    color: var(--color-text-primary);
  }
}

.advanced-content {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-md);
  margin-top: var(--spacing-md);
}

// ═══ Slider Input ═══
.slider-input {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);

  input[type='range'] {
    flex: 1;
    height: 4px;
    background: var(--color-bg-dark);
    border-radius: var(--radius-full);
    appearance: none;

    &::-webkit-slider-thumb {
      appearance: none;
      width: 16px;
      height: 16px;
      background: var(--color-gold);
      border-radius: 50%;
      cursor: pointer;
    }
  }
}

.slider-value {
  min-width: 40px;
  text-align: right;
  font-size: 13px;
  font-family: var(--font-mono);
  color: var(--color-text-secondary);
}

// ═══ Prompt Section ═══
.prompt-section {
  .section-body {
    padding: var(--spacing-md);
  }
}

.btn-expand-section {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
  padding: var(--spacing-xs) var(--spacing-sm);
  background: var(--color-bg-dark);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  color: var(--color-text-secondary);
  font-size: 12px;
  transition: all var(--transition-fast);

  &:hover {
    background: var(--color-bg-elevated);
    color: var(--color-text-primary);
  }
}

// ═══ Warning ═══
.script-warning {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  padding: var(--spacing-md);
  background: rgba(255, 107, 107, 0.1);
  border: 1px solid rgba(255, 107, 107, 0.3);
  border-radius: var(--radius-md);
  color: var(--color-danger);
  font-size: 13px;

  i {
    font-size: 16px;
  }
}

// ═══ Transitions ═══
.fade-enter-active,
.fade-leave-active {
  transition: opacity 0.3s ease;
}

.fade-enter-from,
.fade-leave-to {
  opacity: 0;
}

.expand-enter-active,
.expand-leave-active {
  transition: all 0.3s ease;
  overflow: hidden;
}

.expand-enter-from,
.expand-leave-to {
  opacity: 0;
  max-height: 0;
}

.expand-enter-to,
.expand-leave-from {
  max-height: 500px;
}
