
.ability-radar {
  position: relative;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--spacing-md);
}

.radar-svg {
  width: 100%;
  height: 100%;
  max-width: none;
  aspect-ratio: 1;
}

.grid-line {
  fill: none;
  stroke: var(--color-border);
  stroke-width: 1;
  opacity: 0.4;
}

.axis-line {
  stroke: var(--color-border);
  stroke-width: 1;
  opacity: 0.3;
}

.radar-area {
  fill: rgba(196, 30, 58, 0.15);
  stroke: var(--color-romance);
  stroke-width: 2;
  transition: fill 0.2s ease;
}

.data-point {
  fill: var(--color-romance);
  cursor: pointer;
  transition: all var(--transition-fast);

  &:hover {
    r: 8;
    filter: drop-shadow(0 0 6px var(--color-romance));
  }

  &.highest {
    fill: var(--color-success);
    stroke: white;
    stroke-width: 2;
    r: 7;

    &:hover {
      filter: drop-shadow(0 0 8px var(--color-success));
    }
  }

  &.lowest {
    fill: var(--color-danger);
    stroke: white;
    stroke-width: 2;
    r: 7;

    &:hover {
      filter: drop-shadow(0 0 8px var(--color-danger));
    }
  }
}

.label {
  font-size: 10px;
  fill: var(--color-text-secondary);
  text-anchor: middle;
  pointer-events: none;

  &.highest {
    fill: var(--color-success);
    font-weight: 600;
  }

  &.lowest {
    fill: var(--color-danger);
    font-weight: 600;
  }
}

.radar-legend {
  display: flex;
  justify-content: center;
  gap: var(--spacing-lg);
  flex-wrap: wrap;

  .legend-item {
    display: flex;
    align-items: center;
    gap: var(--spacing-xs);
    font-size: 12px;
    padding: var(--spacing-xs) var(--spacing-sm);
    background: var(--color-bg-elevated);
    border-radius: var(--radius-sm);

    i {
      font-size: 11px;
    }

    &.highest {
      color: var(--color-success);
      background: rgba(74, 193, 142, 0.1);
    }

    &.lowest {
      color: var(--color-danger);
      background: rgba(255, 107, 107, 0.1);
    }
  }
}

// Tooltip
.ability-tooltip {
  position: fixed;
  z-index: 1000;
  padding: var(--spacing-sm) var(--spacing-md);
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  box-shadow: var(--shadow-lg);
  max-width: 280px;
  pointer-events: none;

  h4 {
    font-size: 14px;
    font-weight: 600;
    color: var(--color-text-primary);
    margin-bottom: var(--spacing-xs);
  }

  .value {
    font-size: 13px;
    color: var(--color-gold);
    margin-bottom: var(--spacing-xs);
    display: flex;
    align-items: center;
    gap: var(--spacing-xs);

    .tier {
      font-size: 11px;
      padding: 1px 6px;
      border-radius: var(--radius-sm);
      font-weight: 500;

      &.t0 {
        background: rgba(255, 215, 0, 0.15);
        color: #ffd700;
      }
      &.t1 {
        background: rgba(74, 193, 142, 0.15);
        color: var(--color-success);
      }
      &.t2 {
        background: rgba(122, 162, 247, 0.15);
        color: var(--color-info);
      }
      &.t3 {
        background: rgba(224, 195, 108, 0.15);
        color: var(--color-warning);
      }
      &.t4 {
        background: rgba(255, 107, 107, 0.15);
        color: var(--color-danger);
      }
    }
  }

  .description {
    font-size: 12px;
    color: var(--color-text-secondary);
    line-height: 1.5;
  }
}

// 过渡动画
.fade-enter-active,
.fade-leave-active {
  transition: opacity 0.15s ease;
}

.fade-enter-from,
.fade-leave-to {
  opacity: 0;
}
