
.dashboard {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-md);
  height: 100%;
  min-height: 0;
}

// ═══ 行布局 ═══
.row-1 {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--spacing-md);
  flex-shrink: 0;
}

// 第二行：三栏均分，填满剩余空间
.row-2 {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  gap: var(--spacing-md);
  flex: 1;
  min-height: 0;
}

// ═══ 通用卡片（含hover效果） ═══
.card {
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  overflow: hidden;
  display: flex;
  flex-direction: column;
  min-height: 0;
  position: relative;
  transition:
    transform var(--transition-fast),
    box-shadow var(--transition-fast),
    border-color var(--transition-fast);

  // hover 光泽效果
  &::before {
    content: '';
    position: absolute;
    inset: 0;
    background: linear-gradient(135deg, rgba(255, 255, 255, 0.02) 0%, transparent 60%);
    opacity: 0;
    transition: opacity var(--transition-fast);
    pointer-events: none;
    z-index: 0;
  }

  &:hover {
    transform: translateY(-2px);
    box-shadow: 0 8px 20px rgba(0, 0, 0, 0.3);
    border-color: var(--color-border-light);

    &::before {
      opacity: 1;
    }
  }
}

.card-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--spacing-sm) var(--spacing-md);
  border-bottom: 1px solid var(--color-border);
  flex-shrink: 0;

  &.compact {
    padding: var(--spacing-xs) var(--spacing-md);
  }

  h2 {
    display: flex;
    align-items: center;
    gap: var(--spacing-sm);
    font-size: 13px;
    font-weight: 600;
    color: var(--color-text-primary);

    i {
      color: var(--color-gold);
      font-size: 12px;
    }
  }
}

.card-body {
  padding: var(--spacing-md);
  flex: 1;
  overflow-y: auto;
  min-height: 0;

  &.compact {
    padding: var(--spacing-sm) var(--spacing-md);
  }

  &.scrollable {
    scrollbar-width: thin;
    scrollbar-color: var(--color-border) transparent;

    &::-webkit-scrollbar {
      width: 4px;
    }
    &::-webkit-scrollbar-track {
      background: transparent;
    }
    &::-webkit-scrollbar-thumb {
      background: var(--color-border);
      border-radius: 2px;
    }
  }
}

// ═══ 时空舆情卡（无纵向间距） ═══

.info-list {
  display: flex;
  flex-direction: column;

  &.compact {
    gap: 0;
  }
}

.info-row {
  display: flex;
  align-items: flex-start;
  gap: 6px;
  font-size: 12px;
  line-height: 1.4;
  padding: 2px 0;

  i {
    flex-shrink: 0;
    width: 12px;
    font-size: 10px;
    margin-top: 3px;
  }

  span {
    flex: 1;
    word-break: break-word;
  }

  &.event {
    color: var(--color-gold);
    i {
      color: var(--color-gold);
    }
  }
  &.central {
    color: #9b59b6;
    i {
      color: #9b59b6;
    }
  }
  &.province {
    color: #3498db;
    i {
      color: #3498db;
    }
  }
  &.local {
    color: #1abc9c;
    i {
      color: #1abc9c;
    }
  }
  &.rumor {
    color: var(--color-warning);
    i {
      color: var(--color-warning);
    }
  }
  &.reputation {
    color: var(--color-romance-light);
    i {
      color: var(--color-romance-light);
    }
  }
}

// ═══ 场景卡 ═══
.scene-type {
  padding: 2px 8px;
  font-size: 10px;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-full);
  color: var(--color-text-secondary);
}

.scene-desc {
  font-size: 12px;
  line-height: 1.6;
  color: var(--color-text-secondary);
  margin-bottom: var(--spacing-sm);
  word-break: break-word;
}

.scene-row {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: var(--spacing-xs);
  margin-bottom: var(--spacing-xs);
}

.mood-badge {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 2px 8px;
  font-size: 10px;
  background: rgba(255, 77, 109, 0.1);
  border-radius: var(--radius-sm);
  color: var(--color-romance-light);

  i {
    font-size: 10px;
  }
}

.present-chars {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
}

.topic-badge {
  padding: var(--spacing-xs) var(--spacing-sm);
  background: rgba(216, 166, 87, 0.1);
  border-radius: var(--radius-sm);
  font-size: 11px;
  color: var(--color-gold);
  word-break: break-word;

  i {
    margin-right: 4px;
  }
}

// ═══ 统计卡片 ═══
.stat-card-panel {
  min-width: 0;
}

.stat-body {
  overflow-y: auto;
}

.stat-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.stat-item {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  padding: 8px 12px;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-sm);
  cursor: pointer;
  transition: all var(--transition-fast);

  &:hover {
    background: rgba(255, 255, 255, 0.08);
    transform: translateX(2px);
  }

  .stat-icon {
    width: 32px;
    height: 32px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: var(--color-bg-card);
    border-radius: var(--radius-sm);
    font-size: 14px;
    color: var(--color-gold);
    flex-shrink: 0;
  }

  &.romance .stat-icon {
    background: rgba(255, 77, 109, 0.15);
    color: var(--color-romance-light);
  }
  &.danger .stat-icon {
    background: rgba(255, 107, 107, 0.15);
    color: var(--color-danger);
  }
  &.success .stat-icon {
    background: rgba(74, 193, 142, 0.15);
    color: var(--color-success);
  }

  .stat-info {
    display: flex;
    flex-direction: column;
  }

  .stat-value {
    font-size: 18px;
    font-weight: 700;
    color: var(--color-text-primary);
    font-family: var(--font-display);
    line-height: 1;
  }

  .stat-label {
    font-size: 11px;
    color: var(--color-text-muted);
  }
}

// ═══ 待办事项 ═══
.todo-card {
  min-width: 0;
}

.todo-body {
  overflow-y: auto;
}

.count-badge {
  padding: 2px 6px;
  font-size: 10px;
  font-weight: 600;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-full);
  color: var(--color-text-secondary);
}

.todo-list {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.todo-item {
  display: flex;
  align-items: flex-start;
  gap: 8px;
  padding: 6px 10px;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-sm);
  border-left: 3px solid var(--color-border);
  transition: all var(--transition-fast);

  &.urgent {
    border-left-color: var(--color-danger);
  }
  &.high {
    border-left-color: var(--color-warning);
  }
  &.normal {
    border-left-color: var(--color-info);
  }

  &.completed {
    opacity: 0.5;

    .todo-text {
      text-decoration: line-through;
      color: var(--color-text-muted);
    }
  }
}

.todo-checkbox {
  position: relative;
  display: flex;
  align-items: center;
  cursor: pointer;
  flex-shrink: 0;
  margin-top: 2px;

  input {
    position: absolute;
    opacity: 0;
    cursor: pointer;
    height: 0;
    width: 0;
  }

  .checkmark {
    width: 16px;
    height: 16px;
    border: 2px solid var(--color-border);
    border-radius: 4px;
    background: transparent;
    transition: all var(--transition-fast);
    display: flex;
    align-items: center;
    justify-content: center;

    &::after {
      content: '';
      display: none;
      width: 4px;
      height: 8px;
      border: solid var(--color-success);
      border-width: 0 2px 2px 0;
      transform: rotate(45deg);
      margin-bottom: 2px;
    }
  }

  input:checked + .checkmark {
    border-color: var(--color-success);
    background: rgba(74, 193, 142, 0.1);

    &::after {
      display: block;
    }
  }

  &:hover .checkmark {
    border-color: var(--color-text-muted);
  }
}

.todo-content {
  flex: 1;
  min-width: 0;
}

.todo-main {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-bottom: 2px;
}

.todo-urgency {
  padding: 2px 5px;
  font-size: 10px;
  font-weight: 600;
  background: var(--color-bg-card);
  border-radius: 3px;
  color: var(--color-text-muted);
  flex-shrink: 0;

  .urgent & {
    color: var(--color-danger);
  }
  .high & {
    color: var(--color-warning);
  }
}

.todo-text {
  font-size: 12px;
  color: var(--color-text-primary);
  word-break: break-word;
  line-height: 1.4;
}

.todo-meta {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 4px;
  font-size: 10px;
  color: var(--color-text-muted);

  i {
    margin-right: 2px;
  }
}

.deadline {
  display: flex;
  align-items: center;
}

.more-chars {
  font-size: 10px;
  color: var(--color-text-muted);
}

.empty-hint {
  text-align: center;
  color: var(--color-text-muted);
  font-size: 12px;
  padding: var(--spacing-md);
}

.more-link {
  display: flex;
  align-items: center;
  gap: 4px;
  font-size: 11px;
  color: var(--color-text-muted);
  cursor: pointer;

  &:hover {
    color: var(--color-gold);
  }
}

// ═══ 关系索引（动态颜色，无图标） ═══
.relations-card {
  min-width: 0;
}

.relations-body {
  overflow-y: auto;
}

.relations-card .card-header .more-link {
  display: flex;
  align-items: center;
  gap: 4px;
  font-size: 11px;
  color: var(--color-text-muted);

  &:hover {
    color: var(--color-gold);
  }
}

.relation-row {
  display: flex;
  flex-wrap: wrap;
  gap: 6px 8px;
}

// 关系 chip - 单值字段（无图标，使用动态颜色）
.relation-chip {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 4px 10px;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-sm);
  font-size: 11px;
  border: 1px solid transparent;
  transition: all var(--transition-fast);

  .rel-label {
    font-size: 11px;
    font-weight: 500;
    color: var(--field-color);
  }

  // 第13个及以后的字段：添加边框和降低透明度以示区分
  &.extended {
    border-color: var(--field-color);
    opacity: 0.85;

    .rel-label {
      opacity: 0.9;
    }
  }

  &:hover {
    background: rgba(255, 255, 255, 0.05);
    transform: translateY(-1px);
  }
}

// 关系组 - 数组字段（无图标，使用动态颜色）
.relation-group {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 4px 8px;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-sm);
  border: 1px solid transparent;
  transition: all var(--transition-fast);

  .group-label {
    font-size: 11px;
    font-weight: 500;
    color: var(--field-color);
  }

  .group-tags {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
  }

  // 第13个及以后的字段：添加边框和降低透明度以示区分
  &.extended {
    border-color: var(--field-color);
    opacity: 0.85;

    .group-label {
      opacity: 0.9;
    }
  }

  &:hover {
    background: rgba(255, 255, 255, 0.05);
    transform: translateY(-1px);
  }
}

// ═══ 全局统一角色名样式 ═══
:deep(.character-name) {
  font-size: 11px !important;
  padding: 2px 6px !important;
  margin: 0 1px !important;
  line-height: 1.2 !important;
  white-space: nowrap;

  &.exists {
    background: rgba(100, 100, 100, 0.12) !important;

    &.male {
      background: rgba(74, 144, 217, 0.12) !important;
      color: #5ba0e0 !important;
    }

    &.female {
      background: rgba(232, 67, 147, 0.12) !important;
      color: #e84393 !important;
    }
  }

  &:not(.exists) {
    background: transparent !important;
    padding: 0 !important;
    color: var(--color-text-muted) !important;
  }
}
