
.faction-page {
  display: flex;
  flex-direction: column;
  height: 100%;
}

// ═══ 紧凑单页布局 ═══
.faction-layout {
  display: grid;
  grid-template-columns: 260px 1fr;
  gap: var(--spacing-md);
  height: 100%;
  min-height: 0;
}

// ═══ 左侧：我方派系区域 ═══
.our-faction-section {
  display: flex;
  flex-direction: column;
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  overflow: hidden;

  > .section-header {
    padding: var(--spacing-sm) var(--spacing-md);
    border-bottom: 1px solid var(--color-border);
    flex-shrink: 0;

    h2 {
      display: flex;
      align-items: center;
      gap: var(--spacing-sm);
      font-size: 14px;
      font-weight: 600;
      color: var(--color-gold);

      i {
        color: var(--color-gold);
      }
    }
  }
}

.our-faction-card {
  background: linear-gradient(135deg, rgba(216, 166, 87, 0.08) 0%, transparent 100%);
  padding: var(--spacing-lg);
  display: flex;
  flex-direction: column;
  gap: var(--spacing-md);
  position: relative;
  overflow: hidden;
  flex: 1;

  &::before {
    content: '';
    position: absolute;
    top: 0;
    right: 0;
    width: 100px;
    height: 100px;
    background: radial-gradient(circle at top right, rgba(216, 166, 87, 0.1), transparent);
    pointer-events: none;
  }
}

.faction-badge {
  width: 48px;
  height: 48px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(135deg, var(--color-gold), #e0c36c);
  border-radius: var(--radius-md);
  color: var(--color-bg-dark);
  font-size: 20px;
  box-shadow: 0 4px 12px rgba(216, 166, 87, 0.3);
}

.faction-name {
  font-size: 20px;
  font-weight: 700;
  color: var(--color-gold);
  margin: 0;
}

.faction-core {
  display: flex;
  flex-direction: column;
  gap: 4px;

  .label {
    font-size: 10px;
    color: var(--color-text-muted);
    text-transform: uppercase;
    letter-spacing: 0.5px;
  }

  .core-char {
    font-size: 14px !important;
    padding: var(--spacing-xs) var(--spacing-sm) !important;
  }
}

.faction-stats {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-sm);
}

.stat {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: var(--spacing-xs) var(--spacing-sm);
  background: var(--color-bg-elevated);
  border-radius: var(--radius-sm);

  .stat-label {
    font-size: 11px;
    color: var(--color-text-muted);
  }

  .stat-value {
    font-size: 12px;
    font-weight: 600;
    color: var(--color-text-secondary);

    &.high {
      color: var(--color-success);
    }
    &.mid {
      color: var(--color-info);
    }
    &.low {
      color: var(--color-warning);
    }
  }
}

.our-faction-card .faction-trend {
  display: flex;
  align-items: flex-start;
  gap: var(--spacing-sm);
  padding: var(--spacing-sm);
  background: rgba(216, 166, 87, 0.08);
  border-radius: var(--radius-sm);
  font-size: 12px;
  color: var(--color-text-secondary);
  line-height: 1.5;

  i {
    color: var(--color-gold);
    margin-top: 2px;
    flex-shrink: 0;
  }
}

// ═══ 右侧：主要派系 ═══
.major-factions {
  display: flex;
  flex-direction: column;
  min-height: 0;
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  overflow: hidden;
}

.section-header {
  padding: var(--spacing-sm) var(--spacing-md);
  border-bottom: 1px solid var(--color-border);
  flex-shrink: 0;

  h2 {
    display: flex;
    align-items: center;
    gap: var(--spacing-sm);
    font-size: 14px;
    font-weight: 600;
    color: var(--color-text-primary);

    i {
      color: var(--color-gold);
    }
  }
}

// 派系网格
.factions-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: var(--spacing-sm);
  padding: var(--spacing-sm);
  overflow-y: auto;
  flex: 1;
}

.faction-card {
  padding: var(--spacing-sm) var(--spacing-md);
  background: var(--color-bg-elevated);
  border-radius: var(--radius-md);
  border-left: 3px solid var(--color-border);
  transition:
    transform var(--transition-fast),
    box-shadow var(--transition-fast),
    background var(--transition-fast);

  &:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 16px rgba(0, 0, 0, 0.25);
    background: rgba(255, 255, 255, 0.03);
  }

  &.ally-border {
    border-left-color: var(--color-success);
    &:hover {
      box-shadow: 0 6px 16px rgba(74, 193, 142, 0.15);
    }
  }
  &.enemy-border {
    border-left-color: var(--color-danger);
    &:hover {
      box-shadow: 0 6px 16px rgba(255, 107, 107, 0.15);
    }
  }
}

.card-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: var(--spacing-xs);
}

.card-title {
  font-size: 14px;
  font-weight: 600;
  color: var(--color-text-primary);
}

.relation-tag {
  padding: 2px 8px;
  font-size: 10px;
  font-weight: 600;
  border-radius: var(--radius-full);
  background: var(--color-bg-card);
  color: var(--color-text-muted);

  &.ally {
    background: rgba(74, 193, 142, 0.15);
    color: var(--color-success);
  }
  &.enemy {
    background: rgba(255, 107, 107, 0.15);
    color: var(--color-danger);
  }
  &.neutral {
    background: rgba(122, 162, 247, 0.15);
    color: var(--color-info);
  }
}

.card-body {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.card-leader {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  font-size: 12px;
  color: var(--color-text-secondary);

  i {
    color: var(--color-text-muted);
    font-size: 11px;
  }

  .strength {
    margin-left: auto;
    font-size: 11px;
    font-weight: 600;

    &.high {
      color: var(--color-success);
    }
    &.mid {
      color: var(--color-info);
    }
    &.low {
      color: var(--color-warning);
    }
  }
}

.card-scope,
.card-trend {
  font-size: 11px;
  color: var(--color-text-muted);
  display: flex;
  align-items: flex-start;
  gap: 6px;

  i {
    margin-top: 2px;
    font-size: 10px;
  }
}

.empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: var(--spacing-md);
  padding: var(--spacing-2xl);
  color: var(--color-text-muted);
  flex: 1;

  i {
    font-size: 36px;
    opacity: 0.5;
  }

  p {
    font-size: 13px;
  }
}
