
.assets-secrets-page {
  display: flex;
  flex-direction: column;
  height: 100%;
}

.main-content {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-md);
  height: 100%;
  min-height: 0;
}

// ═══ 第一行：资产概览 + 房产/座驾/白手套 ═══
.row-assets {
  display: grid;
  grid-template-columns: 120px repeat(3, 1fr);
  gap: var(--spacing-sm);
  flex: 1;
  min-height: 0;
}

// 资产概览条（嵌入式）
.overview-bar {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-sm);
}

.overview-item {
  padding: var(--spacing-sm);
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  text-align: center;
  flex: 1;
  display: flex;
  flex-direction: column;
  justify-content: center;

  .ov-label {
    display: block;
    font-size: 9px;
    color: var(--color-text-muted);
    margin-bottom: 2px;
  }

  .ov-value {
    font-size: 16px;
    font-weight: 700;
    color: var(--color-gold);
    font-family: var(--font-display);
  }

  &.danger {
    border-color: rgba(255, 107, 107, 0.3);
    .ov-value {
      color: var(--color-danger);
    }
  }
}

// ═══ 第二行：暗账（高度与第一行一致） ═══
.row-secrets {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: var(--spacing-sm);
  flex: 1;
  min-height: 0;
}

// ═══ 通用分区卡片 ═══
.section-card {
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  display: flex;
  flex-direction: column;
  overflow: hidden;
  min-height: 0;
  transition:
    transform var(--transition-fast),
    box-shadow var(--transition-fast),
    border-color var(--transition-fast);

  &:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 20px rgba(0, 0, 0, 0.25);
    border-color: var(--color-border-light);
  }

  &.danger-section {
    border-color: rgba(255, 107, 107, 0.3);
    &:hover {
      box-shadow: 0 6px 20px rgba(255, 107, 107, 0.15);
    }
  }
  &.handles-section {
    border-color: rgba(216, 166, 87, 0.3);
    &:hover {
      box-shadow: 0 6px 20px rgba(216, 166, 87, 0.15);
    }
  }
  &.mines-section {
    border-color: rgba(224, 195, 108, 0.3);
    &:hover {
      box-shadow: 0 6px 20px rgba(224, 195, 108, 0.15);
    }
  }
  &.debts-section {
    border-color: rgba(122, 162, 247, 0.3);
    &:hover {
      box-shadow: 0 6px 20px rgba(122, 162, 247, 0.15);
    }
  }
}

.section-header {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
  padding: var(--spacing-xs) var(--spacing-sm);
  background: var(--color-bg-elevated);
  border-bottom: 1px solid var(--color-border);
  font-size: 12px;
  font-weight: 600;
  color: var(--color-text-primary);
  flex-shrink: 0;

  i {
    color: var(--color-gold);
    font-size: 11px;
  }

  .danger-section & i {
    color: var(--color-danger);
  }
  .handles-section & i {
    color: var(--color-gold);
  }
  .mines-section & i {
    color: var(--color-warning);
  }
  .debts-section & i {
    color: var(--color-info);
  }

  .count {
    color: var(--color-text-muted);
    font-weight: 400;
  }
}

.view-tabs {
  margin-left: auto;
  display: flex;
  gap: 2px;

  button {
    padding: 2px 6px;
    font-size: 9px;
    background: var(--color-bg-card);
    border-radius: var(--radius-sm);
    color: var(--color-text-muted);
    transition: all var(--transition-fast);

    &:hover {
      color: var(--color-text-secondary);
    }
    &.active {
      background: var(--color-gold);
      color: var(--color-bg-dark);
    }
  }
}

.section-body {
  flex: 1;
  padding: var(--spacing-xs);
  overflow-y: auto;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-xs);
}

// ═══ 资产项目卡片 ═══
.item-card {
  padding: var(--spacing-xs) var(--spacing-sm);
  background: var(--color-bg-elevated);
  border-radius: var(--radius-sm);
  transition:
    background var(--transition-fast),
    transform var(--transition-fast);

  &:hover {
    background: rgba(255, 255, 255, 0.04);
    transform: translateX(2px);
  }
}

.item-main {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 2px;
}

.item-name {
  font-size: 12px;
  font-weight: 600;
  color: var(--color-text-primary);
}

.item-name-char {
  font-size: 12px !important;
  font-weight: 600 !important;
}

.item-value {
  font-size: 11px;
  font-weight: 600;
  color: var(--color-gold);
}

.item-details {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-xs);
  font-size: 10px;
  color: var(--color-text-muted);

  i {
    margin-right: 2px;
    font-size: 9px;
  }

  .safe {
    color: var(--color-success);
  }
  .ok {
    color: var(--color-info);
  }
  .warn {
    color: var(--color-warning);
  }
  .danger {
    color: var(--color-danger);
  }
}

// ═══ Todo List 样式 ═══
.todo-list {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.todo-item {
  display: flex;
  align-items: flex-start;
  gap: 8px;
  padding: 6px 8px;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-sm);
  border-left: 3px solid var(--color-border);
  transition: all var(--transition-fast);

  &:hover:not(.completed) {
    background: rgba(255, 255, 255, 0.04);
    transform: translateX(2px);
  }

  &.held {
    border-left-color: var(--color-danger);
    &:hover:not(.completed) {
      box-shadow: inset 0 0 0 1px rgba(255, 107, 107, 0.15);
    }
  }
  &.holding {
    border-left-color: var(--color-success);
    &:hover:not(.completed) {
      box-shadow: inset 0 0 0 1px rgba(74, 193, 142, 0.15);
    }
  }
  &.mine {
    border-left-color: var(--color-warning);
    &:hover:not(.completed) {
      box-shadow: inset 0 0 0 1px rgba(224, 195, 108, 0.15);
    }
  }
  &.debt {
    border-left-color: var(--color-info);
    &:hover:not(.completed) {
      box-shadow: inset 0 0 0 1px rgba(122, 162, 247, 0.15);
    }
  }

  &.completed {
    opacity: 0.5;
    .todo-title,
    .todo-desc {
      text-decoration: line-through;
      color: var(--color-text-muted);
    }
  }
}

.todo-checkbox {
  position: relative;
  display: flex;
  align-items: center;
  cursor: pointer;
  flex-shrink: 0;
  margin-top: 2px;

  input {
    position: absolute;
    opacity: 0;
    cursor: pointer;
    height: 0;
    width: 0;
  }

  .checkmark {
    width: 14px;
    height: 14px;
    border: 2px solid var(--color-border);
    border-radius: 3px;
    background: transparent;
    transition: all var(--transition-fast);
    display: flex;
    align-items: center;
    justify-content: center;

    &::after {
      content: '';
      display: none;
      width: 3px;
      height: 6px;
      border: solid var(--color-success);
      border-width: 0 2px 2px 0;
      transform: rotate(45deg);
      margin-bottom: 1px;
    }
  }

  input:checked + .checkmark {
    border-color: var(--color-success);
    background: rgba(74, 193, 142, 0.1);

    &::after {
      display: block;
    }
  }

  &:hover .checkmark {
    border-color: var(--color-text-muted);
  }
}

.todo-content {
  flex: 1;
  min-width: 0;
}

.todo-main {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-bottom: 2px;
}

.type-badge {
  width: 18px;
  height: 18px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: var(--radius-sm);
  font-size: 9px;

  &.held {
    background: rgba(255, 107, 107, 0.2);
    color: var(--color-danger);
  }
  &.holding {
    background: rgba(74, 193, 142, 0.2);
    color: var(--color-success);
  }
}

.todo-title {
  font-size: 12px;
  font-weight: 600;
  color: var(--color-text-primary);
  flex: 1;
}

.risk-badge,
.usage-badge,
.mine-type,
.pressure-badge {
  padding: 1px 5px;
  font-size: 9px;
  font-weight: 600;
  border-radius: var(--radius-sm);
  background: var(--color-bg-card);
  color: var(--color-text-muted);
}

.risk-badge {
  &.critical {
    background: rgba(255, 107, 107, 0.2);
    color: var(--color-danger);
  }
  &.high {
    background: rgba(224, 195, 108, 0.2);
    color: var(--color-warning);
  }
}

.pressure-badge {
  &.urgent {
    background: rgba(255, 107, 107, 0.2);
    color: var(--color-danger);
  }
  &.high {
    background: rgba(224, 195, 108, 0.2);
    color: var(--color-warning);
  }
}

.todo-desc {
  font-size: 11px;
  line-height: 1.4;
  color: var(--color-text-secondary);
  margin-bottom: 4px;
  word-break: break-word;
}

.todo-meta {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-xs);
  font-size: 10px;
  color: var(--color-text-muted);

  i {
    margin-right: 2px;
  }

  .fatal {
    color: var(--color-danger);
  }
  .serious {
    color: var(--color-warning);
  }
}

.trigger-badge {
  margin-top: 4px;
  padding: 3px 6px;
  background: rgba(224, 195, 108, 0.1);
  border-radius: var(--radius-sm);
  font-size: 10px;
  color: var(--color-warning);

  i {
    margin-right: 4px;
  }
}

// ═══ 空状态 ═══
.empty-hint {
  color: var(--color-text-muted);
  font-size: 11px;
  font-style: italic;
  text-align: center;
  padding: var(--spacing-sm);
}
