
.slider-field {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-xs);

  &.disabled {
    opacity: 0.5;
    pointer-events: none;
  }
}

.slider-label {
  display: flex;
  justify-content: space-between;
  align-items: center;

  .label-text {
    font-size: 12px;
    color: var(--color-text-muted);
  }

  .label-value {
    font-size: 13px;
    font-weight: 600;
    color: var(--color-text-primary);

    &.high {
      color: var(--color-success);
    }
    &.mid {
      color: var(--color-warning);
    }
    &.low {
      color: var(--color-danger);
    }
  }
}

.slider-wrapper {
  position: relative;
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
}

.slider-track {
  position: absolute;
  left: 0;
  right: 60px; // 为数字输入框留空间
  height: 6px;
  background: var(--color-bg-elevated);
  border-radius: 3px;
  overflow: hidden;
  pointer-events: none;
}

.slider-fill {
  height: 100%;
  border-radius: 3px;
  transition: width 0.15s ease;

  // 默认颜色
  background: var(--color-gold);

  // 分级颜色
  &.high {
    background: linear-gradient(90deg, var(--color-success), #6dd5a0);
  }
  &.mid {
    background: linear-gradient(90deg, var(--color-warning), #f0d78c);
  }
  &.low {
    background: linear-gradient(90deg, var(--color-danger), #ff9999);
  }
}

.slider-input {
  flex: 1;
  height: 24px;
  margin: 0;
  background: transparent;
  cursor: pointer;
  -webkit-appearance: none;
  appearance: none;

  // Webkit 滑块轨道
  &::-webkit-slider-runnable-track {
    height: 6px;
    background: transparent;
    border-radius: 3px;
  }

  // Webkit 滑块把手
  &::-webkit-slider-thumb {
    -webkit-appearance: none;
    appearance: none;
    width: 16px;
    height: 16px;
    margin-top: -5px;
    background: var(--color-text-primary);
    border: 2px solid var(--color-bg-card);
    border-radius: 50%;
    cursor: pointer;
    box-shadow: var(--shadow-sm);
    transition: transform var(--transition-fast);

    &:hover {
      transform: scale(1.1);
    }
  }

  // Firefox 滑块轨道
  &::-moz-range-track {
    height: 6px;
    background: transparent;
    border-radius: 3px;
  }

  // Firefox 滑块把手
  &::-moz-range-thumb {
    width: 16px;
    height: 16px;
    background: var(--color-text-primary);
    border: 2px solid var(--color-bg-card);
    border-radius: 50%;
    cursor: pointer;
    box-shadow: var(--shadow-sm);
    transition: transform var(--transition-fast);

    &:hover {
      transform: scale(1.1);
    }
  }

  &:focus {
    outline: none;

    &::-webkit-slider-thumb {
      box-shadow: 0 0 0 3px rgba(216, 166, 87, 0.3);
    }

    &::-moz-range-thumb {
      box-shadow: 0 0 0 3px rgba(216, 166, 87, 0.3);
    }
  }
}

.number-input {
  width: 52px;
  padding: var(--spacing-xs) var(--spacing-sm);
  background: var(--color-bg-elevated);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  color: var(--color-text-primary);
  font-size: 13px;
  text-align: center;

  &:focus {
    outline: none;
    border-color: var(--color-gold);
  }

  // 隐藏数字输入框的箭头
  &::-webkit-outer-spin-button,
  &::-webkit-inner-spin-button {
    -webkit-appearance: none;
    margin: 0;
  }
  -moz-appearance: textfield;
}

.slider-ticks {
  position: relative;
  height: 16px;
  margin-top: var(--spacing-xs);
  margin-right: 60px; // 与数字输入框对齐
}

.tick {
  position: absolute;
  transform: translateX(-50%);
  font-size: 10px;
  color: var(--color-text-muted);
}
