
.romance-page {
  display: flex;
  flex-direction: column;
  height: 100%;
  overflow: hidden;
}

// ═══ 横向滚动区域 ═══
.romance-carousel {
  flex: 1;
  overflow: hidden;
  perspective: 1000px;
  padding: var(--spacing-sm) 0;
}

.carousel-track {
  display: flex;
  gap: 24px;
  padding: var(--spacing-sm) var(--spacing-lg);
  transition: transform 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94);
}

// ═══ 卡片样式 ═══
.romance-card {
  width: 280px;
  min-width: 280px;
  display: flex;
  flex-direction: column;
  background: linear-gradient(180deg, var(--color-bg-card) 0%, rgba(30, 20, 25, 0.95) 100%);
  border: 2px solid rgba(196, 30, 58, 0.3);
  border-radius: var(--radius-lg);
  overflow: hidden;
  cursor: pointer;
  transition: all 0.35s cubic-bezier(0.25, 0.46, 0.45, 0.94);
  transform-style: preserve-3d;
  box-shadow: 0 10px 40px rgba(0, 0, 0, 0.3);

  &:hover {
    transform: scale(1.08) translateY(-8px);
    border-color: var(--color-romance);
    box-shadow:
      0 25px 60px rgba(196, 30, 58, 0.4),
      0 0 40px rgba(255, 77, 109, 0.25);
    z-index: 10;
  }

  &.selected {
    border-color: var(--color-romance);
    box-shadow: var(--shadow-glow-romance);
  }
}

// 封面区域（与裁剪比例 3:4 一致，所见即所得）
.card-cover {
  position: relative;
  width: 100%;
  aspect-ratio: 3 / 4;
  background: linear-gradient(135deg, rgba(196, 30, 58, 0.5) 0%, rgba(120, 20, 40, 0.4) 100%);
  background-size: cover;
  background-position: center;

  .cover-gradient {
    position: absolute;
    inset: 0;
    background: linear-gradient(
      to bottom,
      transparent 0%,
      transparent 50%,
      rgba(30, 20, 25, 0.8) 85%,
      rgba(30, 20, 25, 1) 100%
    );
  }
}

.upload-btn {
  position: absolute;
  top: var(--spacing-sm);
  right: var(--spacing-sm);
  width: 32px;
  height: 32px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(0, 0, 0, 0.5);
  backdrop-filter: blur(4px);
  border-radius: var(--radius-sm);
  color: white;
  font-size: 14px;
  cursor: pointer;
  opacity: 0;
  transition: all var(--transition-fast);

  .romance-card:hover & {
    opacity: 1;
  }

  &:hover {
    background: var(--color-romance);
    transform: scale(1.1);
  }
}

.favor-badge {
  position: absolute;
  top: var(--spacing-sm);
  left: var(--spacing-sm);
  display: flex;
  align-items: center;
  gap: 4px;
  padding: 4px 10px;
  background: rgba(255, 77, 109, 0.9);
  border-radius: var(--radius-full);
  font-size: 12px;
  font-weight: 600;
  color: white;
  box-shadow: 0 2px 8px rgba(255, 77, 109, 0.4);

  i {
    font-size: 10px;
  }
}

.danger-badge {
  position: absolute;
  bottom: var(--spacing-md);
  left: var(--spacing-sm);
  display: flex;
  align-items: center;
  gap: 4px;
  padding: 4px 8px;
  background: rgba(0, 0, 0, 0.7);
  border-radius: var(--radius-sm);
  font-size: 11px;
  color: white;

  &.critical {
    background: rgba(255, 77, 109, 0.9);
  }
  &.high {
    background: rgba(255, 107, 107, 0.8);
  }
  &.medium {
    background: rgba(224, 195, 108, 0.8);
    color: var(--color-bg-dark);
  }
}

// 信息区域
.card-info {
  flex: 1;
  padding: var(--spacing-sm) var(--spacing-md);
  display: flex;
  flex-direction: column;
  gap: 4px;
}

// 关系阶段 + 情绪状态并列
.status-row {
  display: flex;
  align-items: center;
  gap: 6px;
  flex-wrap: wrap;
}

.char-name {
  font-size: 18px;
  font-weight: 700;
  color: var(--color-text-primary);
  margin: 0;
}

.char-position {
  font-size: 12px;
  color: var(--color-text-secondary);
}

.stage-tag {
  display: inline-block;
  width: fit-content;
  padding: 3px 10px;
  font-size: 11px;
  font-weight: 600;
  background: rgba(255, 77, 109, 0.15);
  border: 1px solid rgba(255, 77, 109, 0.3);
  border-radius: var(--radius-full);
  color: var(--color-romance-light);

  &.hot {
    background: rgba(255, 77, 109, 0.25);
    border-color: var(--color-romance);
    color: var(--color-romance);
  }

  &.cold {
    background: rgba(122, 162, 247, 0.15);
    border-color: rgba(122, 162, 247, 0.3);
    color: var(--color-info);
  }
}

.emotion-tag {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  width: fit-content;
  padding: 3px 8px;
  font-size: 10px;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-full);
  color: var(--color-text-secondary);

  &.positive {
    background: rgba(74, 193, 142, 0.15);
    color: var(--color-success);
  }
  &.negative {
    background: rgba(255, 107, 107, 0.15);
    color: var(--color-danger);
  }
  &.warning {
    background: rgba(224, 195, 108, 0.15);
    color: var(--color-warning);
  }
}

.identity-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
}

.id-tag {
  padding: 2px 6px;
  font-size: 9px;
  background: rgba(255, 77, 109, 0.1);
  border-radius: var(--radius-sm);
  color: var(--color-romance-light);
}

.recent-event {
  display: flex;
  align-items: flex-start;
  gap: 6px;
  margin-top: 4px;
  font-size: 11px;
  color: var(--color-text-muted);
  font-style: italic;
  line-height: 1.4;

  i {
    margin-top: 2px;
    font-size: 10px;
    flex-shrink: 0;
  }
}

// ═══ 滚动指示器 ═══
.scroll-indicator {
  height: 4px;
  background: var(--color-bg-elevated);
  border-radius: 2px;
  margin: 0 var(--spacing-lg);
  position: relative;
  flex-shrink: 0;
}

.scroll-thumb {
  position: absolute;
  height: 100%;
  background: var(--color-romance-gradient);
  border-radius: 2px;
  transition: left 0.1s ease-out;
}

// ═══ 空状态 ═══
.empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: 100%;
  gap: var(--spacing-md);
  color: var(--color-text-muted);

  i {
    font-size: 64px;
    color: var(--color-romance);
    opacity: 0.3;
  }
}

// ═══ 抽屉样式 ═══
.drawer-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.7);
  backdrop-filter: blur(4px);
  opacity: 0;
  visibility: hidden;
  transition: all var(--transition-slow);
  z-index: var(--z-drawer);

  &.open {
    opacity: 1;
    visibility: visible;
  }
}

.romance-drawer {
  position: fixed;
  top: 0;
  right: 0;
  width: 420px;
  max-width: 90vw;
  height: 100%;
  background: var(--color-bg-card);
  border-left: 1px solid var(--color-border);
  transform: translateX(100%);
  transition: transform var(--transition-slow);
  z-index: calc(var(--z-drawer) + 1);
  display: flex;
  flex-direction: column;

  &.open {
    transform: translateX(0);
  }
}

.drawer-header {
  position: relative;
  // 使用 3:4 比例，与裁剪和卡片封面一致
  aspect-ratio: 3 / 4;
  max-height: 50vh; // 限制最大高度
}

.drawer-cover {
  position: absolute;
  inset: 0;
  background: var(--color-romance-gradient);
  background-size: cover;
  background-position: center top; // 优先显示顶部（通常是脸部）

  .cover-gradient {
    position: absolute;
    inset: 0;
    background: linear-gradient(to bottom, transparent 40%, var(--color-bg-card) 100%);
  }
}

.drawer-title-area {
  position: absolute;
  bottom: var(--spacing-md);
  left: var(--spacing-lg);

  h3 {
    font-size: 24px;
    font-weight: 700;
    color: white;
    text-shadow: 0 2px 12px rgba(0, 0, 0, 0.6);
    margin: 0;
  }

  .subtitle {
    font-size: 13px;
    color: rgba(255, 255, 255, 0.8);
  }
}

.drawer-close {
  position: absolute;
  top: var(--spacing-md);
  right: var(--spacing-md);
  width: 36px;
  height: 36px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(0, 0, 0, 0.4);
  backdrop-filter: blur(4px);
  border-radius: var(--radius-sm);
  color: white;
  font-size: 16px;

  &:hover {
    background: rgba(255, 77, 109, 0.6);
  }
}

.drawer-body {
  flex: 1;
  overflow-y: auto;
  padding: var(--spacing-lg);
}

.status-card {
  background: var(--color-bg-elevated);
  border-radius: var(--radius-md);
  padding: var(--spacing-md);
  margin-bottom: var(--spacing-lg);
}

.status-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: var(--spacing-xs) 0;

  .status-label {
    font-size: 12px;
    color: var(--color-text-muted);
  }

  .status-value {
    font-size: 13px;
    color: var(--color-text-secondary);

    &.highlight {
      color: var(--color-romance-light);
      font-weight: 600;
    }
    &.positive {
      color: var(--color-success);
    }
    &.negative {
      color: var(--color-danger);
    }
    &.warning {
      color: var(--color-warning);
    }
  }
}

.danger-meter {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  margin-top: var(--spacing-sm);
  padding-top: var(--spacing-sm);
  border-top: 1px solid var(--color-border);

  .danger-label {
    font-size: 12px;
    color: var(--color-text-muted);
    width: 50px;
  }

  .danger-bar {
    flex: 1;
    height: 8px;
    background: var(--color-bg-card);
    border-radius: 4px;
    overflow: hidden;

    .danger-fill {
      height: 100%;
      background: var(--color-romance-gradient);
      border-radius: 4px;
    }
  }

  .danger-value {
    width: 40px;
    text-align: right;
    font-size: 13px;
    font-weight: 600;
    color: var(--color-romance-light);
  }
}

.detail-section {
  margin-bottom: var(--spacing-lg);

  h4 {
    display: flex;
    align-items: center;
    gap: var(--spacing-sm);
    font-size: 13px;
    font-weight: 600;
    color: var(--color-text-primary);
    margin: 0 0 var(--spacing-sm);

    i {
      color: var(--color-romance-light);
    }
  }

  &.sensitive h4 i {
    color: var(--color-warning);
  }
}

.desc-text {
  font-size: 13px;
  line-height: 1.6;
  color: var(--color-text-secondary);
}

.grip-info {
  background: var(--color-bg-elevated);
  border-radius: var(--radius-md);
  padding: var(--spacing-md);

  &.masked {
    filter: blur(6px);
    user-select: none;
  }
}

.grip-row {
  margin-bottom: var(--spacing-sm);
  &:last-child {
    margin-bottom: 0;
  }

  .grip-label {
    font-size: 11px;
    color: var(--color-text-muted);
    display: block;
    margin-bottom: 2px;
  }

  .grip-value {
    font-size: 13px;
    color: var(--color-text-secondary);
    &.danger {
      color: var(--color-danger);
    }
  }
}

.unmask-btn {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-top: var(--spacing-sm);
  padding: 4px 10px;
  font-size: 12px;
  color: var(--color-text-muted);
  background: var(--color-bg-elevated);
  border-radius: var(--radius-sm);

  &:hover {
    color: var(--color-text-primary);
  }
}

.contact-info {
  display: flex;
  flex-direction: column;
  gap: 4px;

  .contact-type {
    font-size: 12px;
    color: var(--color-romance-light);
  }
  .contact-detail {
    font-size: 13px;
    color: var(--color-text-secondary);
  }
}

// ═══ 图片上传弹窗 ═══
.image-uploader-modal {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(0, 0, 0, 0.8);
  backdrop-filter: blur(4px);
  z-index: 9998;
}

.uploader-dialog {
  width: 460px;
  max-width: 95vw;
  background: var(--color-bg-card);
  border-radius: var(--radius-lg);
  border: 1px solid var(--color-border);
  overflow: hidden;
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.5);
}

.uploader-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--spacing-md) var(--spacing-lg);
  border-bottom: 1px solid var(--color-border);

  h3 {
    display: flex;
    align-items: center;
    gap: var(--spacing-sm);
    font-size: 16px;
    font-weight: 600;
    color: var(--color-text-primary);
    margin: 0;

    i {
      color: var(--color-romance);
    }
  }

  .close-btn {
    width: 32px;
    height: 32px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: transparent;
    border-radius: var(--radius-sm);
    color: var(--color-text-muted);

    &:hover {
      background: var(--color-bg-elevated);
      color: var(--color-text-primary);
    }
  }
}

.uploader-body {
  padding: var(--spacing-lg);
}
